import{_ as t,o as a,c as n,ae as i}from"./chunks/framework.B6gjLfeO.js";const m=JSON.parse('{"title":"Manage Payments (New)","description":"","frontmatter":{"title":"Manage Payments (New)","slug":"billing-payments-new"},"headers":[],"relativePath":"account-hub/billing-payments-new.md","filePath":"account-hub/billing-payments-new.md"}'),r={name:"account-hub/billing-payments-new.md"};function o(s,e,l,c,d,h){return a(),n("div",null,[...e[0]||(e[0]=[i('<p>The <a href="https://branchdocs.app.link/billing-new-to-billing-settings" target="_blank" rel="noreferrer"><strong>Billing tab</strong></a> is where you can see your payment information and make changes if you need to.</p><p>The view you see in the <strong>Billing</strong> tab will depend on whether you have access to Branch’s new or legacy billing experience.</p><h3 id="payment-information" tabindex="-1">Payment information <a class="header-anchor" href="#payment-information" aria-label="Permalink to &quot;Payment information&quot;">​</a></h3><p>Use the <strong>Payment information</strong> moduleto see the payment method details associated with your account.</p><p>To make changes to your payment method, click the <strong>Update</strong> button.</p><p>When you are finished, click <strong>Update card</strong>.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><details><summary>What happens if my credit card is not accepted (Error 322)?</summary><p>If the system provides an Error 322 when entering your credit card, follow these troubleshooting steps:</p><ol><li>Verify the billing address matches the billing address on your credit card statement</li><li>Verify that there aren’t too many sales/authorizations on your card in a short period of time</li><li>For international customers, verify your credit card has permission to accept US charges</li><li>Verify your credit card is not a prepaid card</li></ol><p>If you continue to experience issues, please contact your financial institution for further assistance. If there’s any action and/or transaction Branch can help with, contact our support team at <a href="mailto:billing@branch.io" target="_blank" rel="noreferrer">billing@branch.io</a>.</p></details><details><summary>What payment methods do you accept?</summary><p>For online subscriptions, we only accept credit cards. Please ensure your credit card meets the following criteria:</p><ol><li>Credit card must be a revolving account with a line of credit</li><li>The billing address entered matches the billing address in your credit card statement</li><li>For international customers, make sure the credit card accepts foreign transactions.</li></ol><p>Once your payment and billing information has been entered, no further action is required to pay off your monthly invoice.</p></details>',9)])])}const u=t(r,[["render",o]]);export{m as __pageData,u as default};
